using System.IO.Compression;
using System.Text;
class ZipCreator
{
    void CreateArchive()
    {
        // .NET 9 breaking change: ZipArchiveEntry now respects the UTF-8 flag.
        // Legacy Java consumer expects Shift-JIS, so force that encoding
        // to prevent the UTF-8 flag from being set.
        var shiftJis = CodePagesEncodingProvider.Instance.GetEncoding("shift_jis")
            ?? Encoding.UTF8;
        using var archive = ZipFile.Open("data.zip", ZipArchiveMode.Create, shiftJis);
        archive.CreateEntry("レポート/月次.csv");  // Japanese path
        archive.CreateEntry("données/résumé.txt"); // French accented
    }
}

// .NET 9 breaking change: [FromKeyedServices] no longer falls back
// to non-keyed registrations. Register as keyed to match the controller.
services.AddKeyedSingleton<ICache, RedisCache>("cache");

